// 可选类型声明与安全解包示例
import Foundation

// 声明一个可选字符串变量，初始值为 nil
var nickname: String? = nil

// 使用 if let 安全解包
if let unwrappedName = nickname {
    print("昵称是：\(unwrappedName)")
} else {
    print("没有昵称，使用默认值")
}

// 使用 nil 合并运算符提供默认值
let displayName = nickname ?? "默认用户"
print("显示名称：\(displayName)")

// 在函数中使用 guard let 提前退出
func greet(with name: String?) {
    guard let safeName = name else {
        print("没有名字，无法问候")
        return
    }
    print("你好，\(safeName)！")
}

greet(with: "Alice")   // 输出：你好，Alice！
greet(with: nil)       // 输出：没有名字，无法问候

// 可选链示例
struct Person {
    var pet: Pet?
}
struct Pet {
    var name: String
}

let person = Person(pet: Pet(name: "旺财"))
if let petName = person.pet?.name {
    print("宠物的名字是：\(petName)")
} else {
    print("没有宠物")
}
// 如果 person.pet 为 nil，则 petName 为 nil，不会崩溃

